import React from 'react';
import {
    Row, Col,
    Form,
    Button, ButtonGroup,
    Dropdown,
    // Pagination, InputGroup, FormControl, Container, Table, Modal,
} from 'react-bootstrap';

import VendorDropdown from './VendorDropdown';
import DatePicker from 'react-date-picker';

var QRCode = require('qrcode.react'); // https://www.npmjs.com/package/qrcode.react
// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;


export default class PartForm extends React.Component {
    constructor(...args) {
        super(...args);
        console.log('newRecord', this.props.newRecord)
        if (this.props.newRecord) {
            this.state = {
                code: '',
                name: '',
                date: new Date(),
                type: '',
                catalogCode: '',
                // typeABC: '',    // will be replaced with rank
                rank: 'C', // Default, instead of typeABC
                isSparPart: "FALSE",    // TODO Spelling!
                latestPrice: 0,
                price: 0,
                currentAmount: 0,
                unit: 'Pcs',
                QPU: 1,
                minAmount: 1,
                maxAmount: 1,
                unitToOrder: 0,
                leadTime: 0,
                OP: 0,
                EOQ: 0,
                groupCode: '',
                stockCode: '',
                locationCode: '',
                location: '',
                vendor: null,
                vendorId: '',
                // State data for form, these fields must not match any field in the Model
                partGroupMap: {},
                vendorMap: {}
            }
        } else if (this.props.data && this.props.data.name) {
            // Edit existing part
            // Data Preparation
            let data = this.props.data;
            data['partGroupMap'] = {};
            data['vendorMap'] = {};

            // console.log("Date",typeof(data.date),data.date,Date.parse(data.date));
            data.date = new Date(data.date);

            // console.log('currentAmount',data['currentAmount']);
            if (data['currentAmount'] === null)
                data['currentAmount'] = 0;

            if (!('vendor' in data) || data['vendor'] === null || data['vendor'] === undefined) {
                data['vendor'] = { _id: '', name: '' };
            }
            // data['vendors'] = []; // UNUSED in this form
            data['vendorId'] = data['vendor']._id;
            console.log("data['vendor']._id", data['vendor']._id)

            this.state = data;
            console.log('PartForm', this.state)

        }


    }

    UNSAFE_componentWillMount() {
        this.fetchPartGroups();
        // this.fetchVendors();
    }


    fetchPartGroups() {
        fetch(apiUrl + 'part/group', {
            method: 'GET',
            // body: JSON.stringify(userData),
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(jsonData => {
                // console.log('Success:', JSON.stringify(response));
                let groups = {};
                for (let i = 0; i < jsonData.data.length; i++) {
                    let group = jsonData.data[i];
                    groups[group._id] = group;
                }

                this.setState({ partGroupMap: groups });
                // console.log('groups', groups);
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    selectGroupHandler = (groupCodeId) => {
        console.log("handleSelect", groupCodeId);
        this.setState({
            groupCode: groupCodeId
        });
    }

    selectRankHandler = (rank) => {
        this.setState({
            rank: rank
        })
    }
    selectVendorHandler = (vendorId) => {
        console.log("handleSelect", vendorId);
        this.setState({
            vendorId: vendorId
        });
    }

    // This applies to the entire form
    changeHandler = (e) => {
        console.log('changeHandler', e.target.id, e.target.value)
        this.setState({
            [e.target.id]: e.target.value
        })
    }

    /**
     * Some custom element (eg VendorDropDown) can't be enforced with basic form validation.
     * true - there's error in the form
     */
    otherValidation() {
        console.log(`otherValidation '${this.state.vendorId}'`)
        let badVendorId = this.state.vendorId === null || this.state.vendorId === undefined || this.state.vendorId === '';
        let badGroupCode = this.state.groupCode === null || this.state.groupCode === undefined || this.state.groupCode === '';
        if (badVendorId || badGroupCode) {
            console.log('otherValidation true')
            return true;
        } else {
            console.log('otherValidation false')
            return false;
        }
    }

    submitHandler = event => {
        const form = event.currentTarget;
        event.preventDefault();
        if (form.checkValidity() === false || this.otherValidation()) {
            event.stopPropagation();
            return;
        }

        let part = this.state;
        part.vendor = part.vendorId;
        // part.typeABC = this.state.partGroupMap[part.groupCode].code;

        // Remove vendor list
        // delete part.vendors
        // make the vendor becomes just only ObjectID
        // part.vendor = part.vendor._id

        let method = this.props.newRecord ? 'POST' : 'PUT';
        console.log(method, this.state);
        // clean up
        delete part.transactions
        delete part.partGroup
        delete part.status
        delete part.vendorId

        console.log(part);
        fetch(apiUrl + 'part', {
            method: method,
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            body: JSON.stringify(part)
        })
            .then(response => response.json())
            .then(jsonData => {
                console.log('Success:', JSON.stringify(jsonData));
                this.props.closeFormHandler(true);
            })
            .catch(error => {
                this.props.closeFormHandler(false);
                console.error('Error:', error);
            });

    };

    handleChange = (date) => {
        this.setState({
            date: date
        });
    }

    render() {


        let partGroupArray = Object.values(this.state.partGroupMap); // Dict to Array        
        if (partGroupArray.length === 0)
            return (<h3>Loading..</h3>)

        const partGroupList = partGroupArray.map((group) => {
            // console.log('group',group)
            return (
                // <option key={group._id} value={group.code}>
                //     {group.code} : {group.name}
                // </option>
                <Dropdown.Item
                    key={group._id}
                    eventKey={group._id}
                >
                    {group.code} : {group.name}
                </Dropdown.Item>
            );
        });
        console.log('partGroupArray', partGroupArray)
        console.log('partGroupList[0]', partGroupList[0])

        let groupCode = this.state.groupCode;
        let group = { _id: '', code: '--', name: '' };
        if (groupCode !== undefined && groupCode !== null && groupCode !== '') {
            if (partGroupArray.length > 0) {
                group = this.state.partGroupMap[groupCode]
            }
        } else {
            // default to the first group in the available groups
            groupCode = partGroupArray[0].code
        }

        // console.log('groupCode', groupCode);
        // console.log('group', group)

        return (
            <Form onSubmit={this.submitHandler}>
                <Row>
                    <Col sm={2}>
                        <QRCode includeMargin={true} value={this.state.code} />
                    </Col>
                    <Col sm={10}>
                        <Row>
                            <Col sm={4}>
                                <Form.Group as={Col} controlId="code">
                                    <Form.Label>Part NO.</Form.Label>
                                    <Col size="sm-3">
                                        <Form.Control type="text" placeholder="Part NO."
                                            value={this.state.code}
                                            required
                                            onChange={this.changeHandler} />
                                    </Col>
                                </Form.Group>
                            </Col>
                            <Col>
                                <Form.Group as={Col} controlId="name">
                                    <Form.Label>Part Name</Form.Label>
                                    <Form.Control type="text" placeholder="Part Name"
                                        value={this.state.name}
                                        required
                                        onChange={this.changeHandler} />
                                </Form.Group>
                            </Col>
                        </Row>
                        <Form.Row>
                            <Form.Group as={Col} controlId="type">
                                <Form.Label>Description</Form.Label>
                                <Form.Control placeholder="Description"
                                    value={this.state.type}
                                    required
                                    onChange={this.changeHandler} />
                            </Form.Group>
                        </Form.Row>
                        <Form.Group as={Row} controlId="vendorId">
                            <Form.Label column sm="10">ผู้ขายที่ซื้อล่าสุด:</Form.Label>
                            <Col >
                                <VendorDropdown
                                    preselectVendorId={this.state.vendorId}
                                    selectHandler={this.selectVendorHandler}
                                />
                            </Col>
                        </Form.Group>

                    </Col>
                </Row>

                <Form.Row>
                    <Form.Group controlId="groupCode">
                        <Form.Label>ประเภทวัสดุ</Form.Label>
                        <Dropdown
                            onSelect={this.selectGroupHandler}
                            name="groupCode"
                            id="groupCode">

                            <Dropdown.Toggle variant="outline-dark" id="dropdown-custom-components">
                                {group.name}
                            </Dropdown.Toggle>

                            <Dropdown.Menu>
                                {partGroupList}
                            </Dropdown.Menu>
                        </Dropdown>

                        {/* <Form.Control as="select"
                            variant="outline-dark"
                            value={this.state.groupCode}
                            onChange={this.changeHandler}>
                            {partGroupList}
                        </Form.Control> */}
                    </Form.Group>

                    <Form.Group controlId="latestPrice">
                        <Form.Label>ราคาต่อหน่วย</Form.Label>
                        <Form.Control placeholder="ราคาต่อหน่วย" type="number"
                        step="0.01"
                            value={this.state.latestPrice}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    <Form.Group controlId="date">
                        <Form.Label>วันที่ขึ้นทะเบียน</Form.Label>
                        <Row>
                            <DatePicker
                                format="dd/MM/y"
                                onChange={this.handleChange}
                                value={this.state.date}
                            />
                        </Row>
                    </Form.Group>

                    <Form.Group controlId="unit">
                        <Form.Label>หน่วย</Form.Label>
                        <Form.Control placeholder="หน่วย"
                            value={this.state.unit}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    {/* <Form.Group controlId="stockCode">
                        <Form.Label>Stock Code</Form.Label>
                        <Form.Control placeholder="Stock Code"
                            value={this.state.stockCode}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    <Form.Group controlId="catalogCode">
                        <Form.Label>Catalog Code</Form.Label>
                        <Form.Control placeholder="Catalog Code"
                            value={this.state.catalogCode}
                            onChange={this.changeHandler} />
                    </Form.Group> */}
                    {/* <Form.Group controlId="typeABC">
                        <Form.Label>Group Code</Form.Label>
                        <Form.Control placeholder="Type ABC"
                            value={this.state.typeABC}
                            onChange={this.changeHandler} />
                    </Form.Group> */}
                </Form.Row>
                {/*
                <Form.Row>

                     <Form.Group controlId="price">
                        <Form.Label>ราคา</Form.Label>
                        <Form.Control placeholder="ราคา" type="number"
                            value={this.state.price}
                            onChange={this.changeHandler} />
                    </Form.Group> 
                </Form.Row>
                */}
                <Form.Row>
                    {/* <Form.Group controlId="typeABC">
                        <Form.Label>typeABC</Form.Label>
                        <Form.Control placeholder="typeABC"
                            value={this.state.typeABC}
                            onChange={this.changeHandler} />
                    </Form.Group> */}

                    <Form.Group controlId="rank">
                        <Form.Label>RANK</Form.Label>
                        <Dropdown
                            onSelect={this.selectRankHandler}
                            name="rank"
                            id="rank">

                            <Dropdown.Toggle variant="outline-dark" id="dropdown-custom-components">
                                {this.state.rank}
                            </Dropdown.Toggle>

                            <Dropdown.Menu>
                                <Dropdown.Item key={'A'} eventKey={'A'}>A</Dropdown.Item>
                                <Dropdown.Item key={'B'} eventKey={'B'}>B</Dropdown.Item>
                                <Dropdown.Item key={'C'} eventKey={'C'}>C</Dropdown.Item>
                            </Dropdown.Menu>
                        </Dropdown>
                    </Form.Group>

                    <Form.Group controlId="QPU">
                        <Form.Label>จำนวนต่อหน่วย</Form.Label>
                        <Form.Control placeholder="จำนวนต่อหน่วย" type="number"
                            value={this.state.QPU}
                            onChange={this.changeHandler} />
                    </Form.Group>

                    <Form.Group controlId="currentAmount">
                        <Form.Label>จำนวนปัจจุบัน</Form.Label>
                        <Form.Control placeholder="จำนวนปัจจุบัน" type="number"
                            disabled={!this.state.newRecord}
                            value={this.state.currentAmount}
                            onChange={this.changeHandler} />
                    </Form.Group>

                </Form.Row>
                <Form.Row>
                    <Form.Group controlId="minAmount">
                        <Form.Label>MIN</Form.Label>
                        <Form.Control placeholder="MIN" type="number"
                            value={this.state.minAmount}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    <Form.Group controlId="maxAmount">
                        <Form.Label>MAX</Form.Label>
                        <Form.Control placeholder="MAX" type="number"
                            value={this.state.maxAmount}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    {/* <Form.Group controlId="unitToOrder">
                        <Form.Label>จุดสั่งซื้อ</Form.Label>
                        <Form.Control placeholder="จุดสั่งซื้อ" type="number"
                            value={this.state.unitToOrder}
                            onChange={this.changeHandler} />
                    </Form.Group> */}
                    <Form.Group controlId="OP">
                        <Form.Label>OP</Form.Label>
                        <Form.Control placeholder="OP"
                            value={this.state.OP}
                            onChange={this.changeHandler} />
                    </Form.Group>
                </Form.Row>

                <Form.Row>
                    <Form.Group controlId="leadTime">
                        <Form.Label>Lead Time</Form.Label>
                        <Form.Control placeholder="Lead Time"
                            value={this.state.leadTime}
                            onChange={this.changeHandler} />
                    </Form.Group>

                    {/* <Form.Group controlId="EOQ">
                        <Form.Label>EOQ</Form.Label>
                        <Form.Control placeholder="EOQ"
                            value={this.state.EOQ}
                            onChange={this.changeHandler} />
                    </Form.Group> */}
                </Form.Row>

                <Form.Row>
                    {/* <Form.Group controlId="typeABC">
                        <Form.Label>RANK</Form.Label>
                        <Form.Control placeholder="RANK"
                            value={this.state.typeABC}
                            onChange={this.changeHandler} />
                    </Form.Group> */}
                    <Form.Group controlId="locationCode">
                        <Form.Label>STOCK NO.</Form.Label>
                        <Form.Control placeholder="STOCK NO."
                            value={this.state.locationCode}
                            onChange={this.changeHandler} />
                    </Form.Group>
                    {/* <Form.Group controlId="location">
                            <Form.Label>ตำแหน่งที่เก็บวัสดุ</Form.Label>
                        <Form.Control placeholder="ตำแหน่งที่เก็บวัสดุ"
                            value={this.state.location}
                            onChange={this.changeHandler} />
                    </Form.Group> */}

                </Form.Row>

                <div className="d-flex flex-column">
                    <ButtonGroup >
                        <Button variant="success" type="submit">
                            บันทึก
                        </Button>
                        <Button variant="outline-secondary"
                            onClick={(e) => this.props.closeFormHandler(false)}>
                            ยกเลิก
                        </Button>
                    </ButtonGroup>
                </div>
            </Form>
        );
    }
}
