// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

/*
 * Format numeric value to #,###.00 (String) 
 */
export function numFormat(x) {
    x = x.toFixed(2);
    var parts = x.toString().split(".");
    parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    // console.log('numFormat',parts.join("."))
    return parts.join(".");
}

/**
 * Load all vendors into a list
 * @param {*} next 
 * @param {*} err 
 */
export function fetchVendors(next, err) {

    let url = apiUrl + 'vendor';

    fetch(url,
        {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
        .then(response => response.json())
        .then(next)
        .catch(err);
}

