import React from 'react';
import PropTypes from 'prop-types';
import {
    Col,
    Form,
    Button, ButtonGroup,
    // Row, Container, Table,
    // Pagination, InputGroup, FormControl,
    // Modal
} from 'react-bootstrap';
// import { prototype } from 'stream';

// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;
const forge = require('node-forge');

export default class UserPasswordForm extends React.Component {


    constructor(...args) {
        super(...args);
        let user = this.props.user;
        let pwd = {
            password: '',
            password2: ''
        }
        this.state = { ...user, ...pwd };
    }

    changeHandler = (e) => {
        this.setState({
            [e.target.id]: e.target.value
        })
    }

    submitHandler = event => {
        const form = event.currentTarget;
        event.preventDefault();
        if (form.checkValidity() === false) {
            event.stopPropagation();
        }

        if (this.state.password !== this.state.password2) {
            // event.stopPropagation();
            alert("รหัสผ่านใหม่ และ รหัสยืนยันไม่เหมือนกัน");
            this.setState({
                password: '',
                password2: ''
            })
            return;
        }


        // must copy, React is serious about controlled input, in this case, password2
        let user = { ...this.state };
        delete user.password2;

        var md = forge.md.sha256.create();
        md.update(user.password);
        user.password = md.digest().toHex();



        let responseStatus;
        let method = this.props.newRecord ? 'POST' : 'PUT';
        console.log("submitHandler:", method, this.state);

        fetch(apiUrl + 'user', {
            method: method,
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            body: JSON.stringify(user)
        })
            .then(response => {
                responseStatus = response.ok;
                return response.json();
            })
            .then(json => {
                if (responseStatus) {
                    console.log(responseStatus, JSON.stringify(json));
                    this.props.closeFormHandler(true, "แก้ไขรหัสผ่านแล้ว");
                } else {
                    this.props.closeFormHandler(true, json.message);
                }
            })
            .catch(error => {
                console.error('Error:', error);
                this.props.closeFormHandler(false);
            });

    };

    render() {
        return (
            <Form onSubmit={this.submitHandler}>
                <Form.Group as={Col} controlId="password">
                    <Form.Label>รหัสผ่านใหม่</Form.Label>
                    <Form.Control type="password" placeholder="รหัสผ่านใหม่"
                        value={this.state.password}
                        onChange={this.changeHandler} />
                </Form.Group>
                <Form.Group as={Col} controlId="password2">
                    <Form.Label>ยืนยันรหัสผ่าน</Form.Label>
                    <Form.Control type="password" placeholder="ยืนยันรหัสผ่าน"
                        value={this.state.password2}
                        onChange={this.changeHandler} />
                </Form.Group>


                <div className="d-flex flex-column">
                    <ButtonGroup >
                        <Button variant="success" type="submit">
                            บันทึก
                        </Button>
                        <Button variant="outline-secondary"
                            onClick={this.props.closeFormHandler}>
                            ยกเลิก
                        </Button>
                    </ButtonGroup>
                </div>
            </Form>
        );
    }
}

UserPasswordForm.propTypes = {
    user: PropTypes.object,
    closeFormHandler: PropTypes.func
};
