import React from 'react';
import {
    Container, Table,

} from 'react-bootstrap';
// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class PartGroup extends React.Component {
    constructor(...args) {
        super(...args);
        this.state = {
            partGroups: []
        }
    }

    UNSAFE_componentWillMount() {
        this.fetchPartGroups();
    }

    fetchPartGroups() {
        fetch(apiUrl + 'part/group', {
            method: 'GET',
            // body: JSON.stringify(userData),
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(response => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({ partGroups: response.data });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }


    render() {
        const list = this.state.partGroups.map((v, i) => {
            return (
                <tr key={i}>
                    <td>---</td>
                    <td>{v.code}</td>
                    <td>{v.name}</td>
                    <td>{v.description}</td>
                </tr>
            )
        });

        return (
            <Container>
                <h2>กลุ่มวัสดุ / อะไหล่</h2>
                <Table striped bordered hover size="sm">
                    <thead>
                        <tr>
                            <th>#</th>
                            <th>Code</th>
                            <th>Name</th>
                            <th>Description</th>
                        </tr>
                    </thead>
                    <tbody>
                        {list}
                    </tbody>
                </Table>
            </Container>
        );
    }
}
