import React from 'react';
import {
    Row, Col,
    Container, Table,
    Pagination, InputGroup, FormControl,
    Button,
    Modal
} from 'react-bootstrap';

import VendorForm from './VendorForm';
import {
    FaPhoneSquare, FaFax,
    FaRegEnvelope, FaTrash, FaEdit,
    FaTimes, FaPlus,
    FaAngleLeft, FaAngleRight
} from 'react-icons/fa';


// import { MdWebAsset } from "react-icons/md";
// const config = require('./config.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class Vendor extends React.Component {

    constructor(...args) {
        super(...args);
        this.state = {
            q: '',
            vendors: [],
            activePage: 1,
            totalPages: 1,
            totalVendors: 0,
            itemsPerPage: 20,
            // modalShow: true, // Test Form
            modalShow: false,
            modelShowConfirm: false,
            modalShowResult: false,
            message: ''
        }
    }

    UNSAFE_componentWillMount() {
        this.fetchTotalVendors();
        this.fetchVendors();
    }

    fetchTotalVendors() {
        fetch(apiUrl + 'vendor/count', {
            method: 'GET',
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => response.json())
            .then(response => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({
                    totalVendors: response.data,
                    totalPages: parseInt(response.data / this.state.itemsPerPage + 0.5)
                });
            })
            .catch(error => {
                console.error('Error:', error);
            });
    }

    fetchVendors(q = '', page = 1) {
        // IF q = null, get all vendors
        console.log('fetchVendors', q);

        let skip = (page - 1) * this.state.itemsPerPage;
        let limit = this.state.itemsPerPage;

        console.debug("fetchVendors", skip, limit);
        let url;
        if (q !== '' && q !== null) {
            url = apiUrl + 'vendor/search/' + q;
        } else {
            url = apiUrl + 'vendor?skip=' + skip + '&limit=' + limit;
        }
        console.log('url', url);

        fetch(url,
            {
                method: 'GET',
                params: { skip: skip, limit: limit },
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                }
            })
            .then(response => response.json())
            .then(response => {
                // console.log('Success:', JSON.stringify(response));
                this.setState({
                    vendors: response.data,
                    activePage: page
                });
            })
            .catch(error => {
                console.error(error);
            });
    }

    prevPageHandler = () => {
        let activePage = parseInt(this.state.activePage);
        if (activePage === 0) return;
        // console.log('Prev Page:', activePage);

        this.setState(
            { q: '' },
            () => this.fetchVendors('', activePage - 1)
        );
    }

    nextPageHandler = () => {
        let activePage = parseInt(this.state.activePage);
        if (activePage === this.state.totalPages) return;
        // console.log('Next Page:', activePage);
        this.setState(
            { q: '' },
            () => this.fetchVendors(null, activePage + 1)
        );
    }

    searchChangeHandler = (e) => {
        this.setState({ q: e.target.value });
    }

    searchVendors = () => {
        let q = this.state.q;
        console.log("Searching ", q);
        this.fetchVendors(q);
    }

    clearSearch = (e) => {
        let _this = this;
        this.setState(
            { q: '' },
            () => {
                _this.searchVendors();
            }
        );

    }

    closeFormHandler = (updateList = false, message = '') => {
        this.setState({ modalShow: false },
            () => {
                if (updateList)
                    this.fetchVendors();
            });
    }

    addHandler = () => {
        this.vendor = {};
        this.setState({ modalShow: false })
    }

    vendor = {};
    confirmDelete = (vendor) => {
        this.vendor = vendor;
        this.setState({
            modelShowConfirm: true
        })
    }

    deleteHandler = (id) => {
        console.log(id);
        this.setState({ modelShowConfirm: false },
            () => fetch(apiUrl + 'vendors', {
                method: 'DELETE',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                body: JSON.stringify({ id: id })
            })
                .then(response => response.json())
                .then(response => {
                    console.log('Delete Success:', JSON.stringify(response));
                    this.setState({
                        modalShowResult: true,
                        message: 'ลบข้อมูลผู้ขายแล้ว'
                    },
                        () => this.fetchVendors()
                    );
                })
                .catch(error => {
                    console.error('Error:', error);
                })
        );
    }

    editHandler = (vendor) => {
        console.log(vendor);
        this.vendor = vendor;
        this.setState({ modalShow: true });
    }

    render() {
        const list = this.state.vendors.map((v, i) => {
            return (
                <tr key={i}>
                    <td>
                        <FaEdit onClick={(e) => this.editHandler(v)} />
                        <FaTrash onClick={(e) => this.confirmDelete(v)} />
                    </td>
                    <td>{v.code}</td>
                    <td>
                        <a href={v.www}>{v.name}</a><br />
                        {v.details}
                        <Row>
                            <Col>
                                <FaPhoneSquare /> {v.tel}<br />
                                <FaPhoneSquare /> {v.phone}<br />
                            </Col>
                            <Col>
                                <FaFax /> {v.fax}<br />
                                <FaRegEnvelope /> {v.email}
                            </Col>
                        </Row>
                    </td>
                </tr >
            )
        });

        let activePage = this.state.activePage;
        let totalPages = this.state.totalPages;
        console.log('activePage', activePage + '/' + totalPages)
        let paginationItems = [];
        paginationItems.push(
            <Pagination.Item key={0} disabled={1 === activePage} onClick={this.prevPageHandler}>
                <FaAngleLeft /> หน้าก่อน
            </Pagination.Item>
        );
        paginationItems.push(
            <Pagination.Item key={-1} disabled={this.state.totalPages === activePage} onClick={this.nextPageHandler}>
                หน้าถัดไป <FaAngleRight />
            </Pagination.Item>
        );
        // for (let number = 1; number <= totalPages; number++) {
        //     paginationItems.push(
        //         <Pagination.Item key={number} active={number === activePage}>
        //             {number}
        //         </Pagination.Item>
        //     );
        // }

        return (
            <>
                <Container>
                    <Row>
                        <Col>
                            <h2>ผู้จัดจำหน่าย ({this.state.totalVendors})</h2>
                        </Col>
                        <Col sm={4}>
                            <Button variant="success" onClick={() => this.setState({ modalShow: true })}>
                                <FaPlus /> เพิ่มผู้จัดจำหน่าย
                        </Button>
                        </Col>
                    </Row>
                    <Row>
                        <Col>
                            <InputGroup className="mb-3">
                                <FormControl
                                    placeholder="ค้นหาด้วยชื่อบริษัท"
                                    aria-label="ค้นหาด้วยชื่อบริษัท"
                                    aria-describedby="basic-addon2"
                                    value={this.state.q}
                                    onChange={this.searchChangeHandler}
                                    onKeyPress={event => {
                                        if (event.key === "Enter") {
                                            this.searchVendors();
                                        }
                                    }}
                                />
                                <InputGroup.Append>
                                    <Button variant="outline-secondary"
                                        onClick={this.searchVendors}>
                                        ค้นหา
                                </Button>
                                    <Button variant="outline-secondary"
                                        onClick={this.clearSearch}>
                                        <FaTimes />
                                    </Button>
                                </InputGroup.Append>
                            </InputGroup>

                        </Col>
                        <Col><Pagination size="sm">{paginationItems}</Pagination></Col>
                    </Row>


                    <Table striped bordered hover size="sm">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th>Code</th>
                                <th>Name</th>
                            </tr>
                        </thead>
                        <tbody>
                            {list}
                        </tbody>
                    </Table>
                </Container>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.modalShow}
                    onHide={this.addHandler}
                >
                    <Modal.Header closeButton>
                        <Modal.Title id="contained-modal-title-vcenter">
                            เพิ่มผู้จัดจำหน่าย
                        </Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <VendorForm
                            closeFormHandler={this.closeFormHandler}
                            data={this.vendor}
                        />
                    </Modal.Body>
                    {/* <Modal.Footer>
                        <Button onClick={()=>this.setState({modalShow:false})}>Close</Button>
                    </Modal.Footer> */}
                </Modal>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.modalShowResult}
                    onHide={() => this.setState({ modalShowResult: false })}
                >

                    <Modal.Body>
                        {this.state.message}
                    </Modal.Body>
                    <Modal.Footer>
                        <Button onClick={() => this.setState({ modalShowResult: false })}>ปิด</Button>
                    </Modal.Footer>
                </Modal>

                <Modal
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    centered
                    show={this.state.modelShowConfirm}
                    onHide={() => this.setState({ modelShowConfirm: false })}
                >

                    <Modal.Body>
                        ยืนยันลบข้อมูล {this.vendor.name}
                    </Modal.Body>
                    <Modal.Footer>
                        <Button variant="danger" onClick={() => this.deleteHandler(this.vendor._id)}>ลบ</Button>
                        <Button variant="outline-secondary" onClick={() => this.setState({ modelShowConfirm: false })}>ยกเลิก</Button>
                    </Modal.Footer>
                </Modal>
            </>
        );
    }
}
