import React from 'react';
import PropTypes from 'prop-types';
import {
    Container, Form, Button,
    Row, Col,

} from 'react-bootstrap';

import packageJson from '../package.json';
const apiUrl = process.env.REACT_APP_API_URL;
const forge = require('node-forge');


export default class LogIn extends React.Component {

    
    // ::: ทดลอง Demo Staff User :::
    // email: mchayapol@gmail.com
    // password: aaa

    constructor(...args) {
        super(...args);
        if (process.env.NODE_ENV === 'development') {
            this.state = {
                email: 'narisa.s@hlt.co.th',
                password: 'aaa'
            }
        } else {
            this.state = {
                email: '',
                password: ''
            }
        }
    }

    handleChange = (e) => {
        this.setState({
            [e.target.name]: e.target.value
        });
    }

    handleSubmit = (e) => {
        // console.log(config)
        e.preventDefault();

        let md = forge.md.sha256.create();
        md.update(this.state.password);
        let password = md.digest().toHex();

        let userData = {
            logemail: this.state.email,
            logpassword: password
        }

        let isOk = false;

        fetch(apiUrl + 'user/login', {
            method: 'POST',
            body: JSON.stringify(userData),
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            }
        })
            .then(response => {
                isOk = response.ok;
                return response.json();
            })
            .then(jsonData => {
                // console.log('Success:', JSON.stringify(response));
                if (isOk) {
                    this.props.handleLoginSuccess(jsonData.data);
                } else {
                    this.props.handleLoginFailure(jsonData);
                }
            })
            .catch(error => {
                console.error('Error:', error);
            });


    }

    render() {
        return (
            <Container fluid>
                <Row className="justify-content-md-center"
                    style={{
                        height: '100vh',
                        width: '100%',
                        left: 0,
                        padding: 0
                    }}>
                    <Col sm={6} style={{
                        // backgroundImage: 'url(https://source.unsplash.com/random)',
                        backgroundImage: 'url(https://source.unsplash.com/collection/8443373/inventory)',
                        backgroundRepeat: 'no-repeat',
                        backgroundSize: 'cover',
                        backgroundPosition: 'center',
                    }}>
                    </Col>
                    <Col sm={6}>
                        <h3>Honda Lock: Spare Parts Maintenance Management System</h3>
                        <span style={{color: '#a0a0a0'}}>Version: {packageJson.version}-{process.env.NODE_ENV}</span>
                        <Form onSubmit={this.handleSubmit}>
                            <Form.Group>
                                <Form.Control name="email" type="text" placeholder="E-mail" value={this.state.email} onChange={this.handleChange} />
                            </Form.Group>
                            <Form.Group>
                                <Form.Control name="password" type="password" placeholder="Password" value={this.state.password} onChange={this.handleChange} />
                            </Form.Group>
                            {/* <Form.Group controlId="formBasicChecbox">
                                <Form.Check type="checkbox" label="Remember me" />
                            </Form.Group> */}
                            <Button variant="success" type="submit">
                                Log In
                                </Button>
                        </Form>                    
                    </Col>
                </Row>
            </Container>
        );
    }
}

LogIn.propTypes = {
    handleLoginSuccess: PropTypes.func,
    handleLoginFailure: PropTypes.func,
};